@startuml
class CollectingEvent {
    -dwcVerbatimLatitude
    -dwcVerbatimLongitude
    -dwcVerbatimLocality
    -verbatimEventDateTime
    -geographicPlaceNameSource
    -collectors
    -attachments
}

class GeographicPlaceNameSourceDetail {
    -sourceUrl
    -country
    -stateProvince
    -higherGeographicPlaces
    -recordedOn
}

class GeoreferenceAssertion {
    -dwcDecimalLatitude
    -dwcDecimalLongitude
    -dwcCoordinateUncertaintyInMeters
    -georeferencedBy
    -dwcGeoreferenceVerificationStatus
}

class MaterialSample {
    -materialSampleName
    -dwcCatalogueNumber[not unique]
    -dwcOtherCatalogNumbers
    -preparedBy
    -preparationDate
}

class Determination {
    -scientificName
    -determinationDate
}

class PreparationType {
    -name
    -description
}

class MaterialSampleType {
    -name
    -description
}

class StorageUnit {
    -name
    -type
}

CollectingEvent ..> GeographicPlaceNameSourceDetail : 1
CollectingEvent ..> GeoreferenceAssertion : 1
CollectingEvent ..> MaterialSample : 0..1
MaterialSample ..> Determination : 0..1
MaterialSample ..> PreparationType : 0..1
MaterialSample ..> MaterialSampleType : 0..1
MaterialSample ..> StorageUnit : 0..1

@enduml
